+    #[test]
+    fn test_ad_hoc_execute_reuses_prepared_simple_insert_fast_path() {
+        let _profile_guard = StatementReuseHotPathProfileGuard::new();
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute("CREATE TABLE t(id INTEGER PRIMARY KEY, name TEXT, score INTEGER);")
+            .unwrap();
+
+        reset_statement_reuse_measurement(&conn);
+        let sql = "INSERT INTO t VALUES (NULL, 'fixed_name', 7);";
+        conn.execute(sql).unwrap();
+        conn.execute(sql).unwrap();
+
+        let profile = hot_path_profile_snapshot();
+        assert_eq!(
+            profile.parser.prepared_cache_misses, 1,
+            "first ad-hoc execute() should seed the prepared cache: {profile:?}"
+        );
+        assert_eq!(
+            profile.parser.prepared_cache_hits, 1,
+            "second identical ad-hoc execute() should reuse the prepared cache: {profile:?}"
+        );
+        assert_eq!(
+            profile.prepared_insert_fast_lane_hits, 2,
+            "ad-hoc execute() should route simple INSERTs through the prepared direct fast lane: {profile:?}"
+        );
+
+        let rows = conn
+            .query("SELECT id, name, score FROM t ORDER BY id;")
+            .unwrap();
+        assert_eq!(rows.len(), 2);
+        assert_eq!(rows[0].values()[0], SqliteValue::Integer(1));
+        assert_eq!(rows[0].values()[1], SqliteValue::Text("fixed_name".into()));
+        assert_eq!(rows[0].values()[2], SqliteValue::Integer(7));
+        assert_eq!(rows[1].values()[0], SqliteValue::Integer(2));
+        assert_eq!(rows[1].values()[1], SqliteValue::Text("fixed_name".into()));
+        assert_eq!(rows[1].values()[2], SqliteValue::Integer(7));
+    }
